// src/packages/index.ts
function registerPackageSkills(registry2, packages) {
  registry2.register({
    name: "package.list",
    version: "1.0.0",
    description: "List installed packages with their manifest provenance: ref (name@version), kind, declared capabilities, engine-compat range, content hash, and whether the package is attested.",
    category: "system",
    permissions: [],
    input: external_exports.object({ name: external_exports.string().optional() }),
    output: external_exports.object({
      packages: external_exports.array(external_exports.object({
        ref: external_exports.string(),
        name: external_exports.string(),
        version: external_exports.string(),
        kind: external_exports.string(),
        declaredCapabilities: external_exports.array(external_exports.string()),
        engineCompat: external_exports.string(),
        contentHash: external_exports.string(),
        attested: external_exports.boolean()
      }))
    }),
    handler: (input) => {
      const pkgs = packages.list().filter((p) => input.name === void 0 || p.manifest.name === input.name);
      return {
        packages: pkgs.map((p) => ({
          ref: p.ref,
          name: p.manifest.name,
          version: p.manifest.version,
          kind: p.manifest.kind,
          declaredCapabilities: p.manifest.declaredCapabilities,
          engineCompat: p.manifest.engineCompat,
          contentHash: p.contentHash,
          attested: p.manifest.attestation !== void 0
        }))
      };
    }
  });
  registry2.register({
    name: "package.load",
    version: "1.0.0",
    description: "Load an installed package (by name@version ref) under a profile: validates the manifest, checks engine-compat (out-of-bounds rejected), gates declared-vs-granted capabilities via the policy engine (over-claim denied), and loads the untrusted entry into the M6 sandbox. Returns the load decision + provenance event id.",
    category: "system",
    permissions: ["agent.write"],
    input: external_exports.object({
      ref: external_exports.string(),
      agentId: external_exports.string(),
      sessionId: external_exports.string(),
      profile: external_exports.string()
    }),
    output: external_exports.object({
      ok: external_exports.boolean(),
      ref: external_exports.string(),
      agentId: external_exports.string().nullable(),
      rule: external_exports.string().nullable(),
      rejectReason: external_exports.string().nullable(),
      reason: external_exports.string().nullable(),
      loadEventId: external_exports.string().nullable()
    }),
    handler: (input, ctx) => {
      const res = packages.load(input.ref, {
        agentId: input.agentId,
        sessionId: input.sessionId,
        profile: input.profile,
        tick: ctx.tick
      });
      return {
        ok: res.ok,
        ref: res.ref,
        agentId: res.agentId ?? null,
        rule: res.decision?.rule ?? null,
        rejectReason: res.rejectReason ?? null,
        reason: res.reason ?? null,
        loadEventId: res.loadEventId ?? null
      };
    }
  });
}

